import pika
import json
from threading import Thread

connection = pika.BlockingConnection(pika.ConnectionParameters('localhost', 5672))
channel = connection.channel()

task_queue = 'task_queue'
result_queue = 'result_queue'

channel.queue_declare(queue=task_queue)
channel.queue_declare(queue=result_queue)

def send_task(task):
    channel.basic_publish(exchange='', routing_key=task_queue, body=json.dumps(task))

def on_task_received(ch, method, properties, body):
    task = json.loads(body)
    print(" [x] Received task:", task)
    # Process the task here (e.g., by performing a time-consuming operation and returning the result)
    result = {
        'task_id': task['id'],
        'result': task['operation'] * 10,
    }
    channel.basic_publish(exchange='', routing_key=result_queue, body=json.dumps(result))
    print(" [x] Sent result:", result)

def on_task_sent(ch, method_frame, header_frame, body):
    print(" [x] Task sent")

def worker():
    channel.basic_consume(queue=task_queue, on_message_callback=on_task_received, auto_ack=True)
    print(' [*] Waiting for messages. To exit press CTRL+C')
    channel.start_consuming()

def publisher():
    tasks = [
        {'id': 1, 'operation': 5},
        {'id': 2, 'operation': 7},
        {'id': 3, 'operation': 9},
    ]

    for task in tasks:
        send_task(task)
        print(" [x] Sent task:", task)
    channel.stop_consuming()

if __name__ == '__main__':
    publisher_thread = Thread(target=publisher)
    worker_thread = Thread(target=worker)

    publisher_thread.start()
    worker_thread.start()

    publisher_thread.join()
    connection.close()